from typing import List

def findMaxAveragePath(matrix: List[List[int]]) -> float:
    n = len(matrix)

    if n == 0:
        return 0

    dp = [[[0.0 for _ in range(n)] for _ in range(n)] for _ in range(n)]

    # Initialize base case
    for i in range(n):
        for j in range(n):
            dp[i][j][1] = matrix[i][j]

    # Fill DP table
    for length in range(2, n + 1):
        for i in range(n):
            for j in range(n):
                max_avg = float('-inf')
                for di, dj in [(-1, 0), (1, 0), (0, -1), (0, 1)]:
                    ni, nj = i + di, j + dj
                    if 0 <= ni < n and 0 <= nj < n:
                        max_avg = max(max_avg, dp[ni][nj][length - 1])
                dp[i][j][length] = matrix[i][j] + max_avg

    # Find maximum average path in the last row
    max_average = float('-inf')
    for j in range(n):
        current_avg = sum(dp[j][n-1]) / n
        max_average = max(max_average, current_avg)

    return round(max_average, 2)

