def convert_tuple_string_to_int(tuple_str):
    import ast

    # Validate the input string format
    if not (tuple_str.startswith('(') and tuple_str.endswith(')')):
        raise ValueError("Invalid tuple string format")

    # Safely evaluate the string into a tuple object
    try:
        result = ast.literal_eval(tuple_str)
    except Exception as e:
        raise ValueError(f"Failed to evaluate tuple string: {e}")

    # Check if the evaluated result is indeed a tuple containing integers
    if not isinstance(result, tuple) or not all(isinstance(i, int) for i in result):
        raise ValueError("Evaluated result is not a tuple of integers")

    # Convert each element of the tuple from a string to an integer using list comprehension
    return tuple(int(item) for item in result)

