def find_right_insertion_point(sorted_list, target_value):
    if not sorted_list:
        return 0

    left = 0
    right = len(sorted_list)

    while left < right:
        mid = left + (right - left) // 2
        if sorted_list[mid] < target_value:
            left = mid + 1
        else:
            right = mid

    return left

